requests.delegateSetup:
#graphql
  mutation BackupRegionUpdateAccessBlockerDelegateSetup {
    delegateAccessTokenCreate(input: { delegateAccessScope: ["read_products"], expiresIn: 300 }) {
      delegateAccessToken {
        accessToken
        accessScopes
        createdAt
        expiresIn
      }
      userErrors {
        field
        message
        code
      }
    }
  }

requests.backupRegionUpdate:
mutation BackupRegionUpdateIdempotent {
  backupRegionUpdate(region: { countryCode: CA }) {
    backupRegion {
      __typename
      id
      name
      ... on MarketRegionCountry {
        code
      }
    }
    userErrors {
      field
      message
      code
    }
  }
}

requests.delegateCleanup:
#graphql
  mutation BackupRegionUpdateAccessBlockerDelegateCleanup($token: String!) {
    delegateAccessTokenDestroy(accessToken: $token) {
      status
      userErrors {
        field
        message
        code
      }
    }
  }

